/// <reference lib="webworker" />
import { precacheAndRoute, cleanupOutdatedCaches } from 'workbox-precaching';
import { clientsClaim } from 'workbox-core';

declare let self: ServiceWorkerGlobalScope;

// Take control immediately
self.skipWaiting();
clientsClaim();

// Precache all assets generated by Vite
cleanupOutdatedCaches();
precacheAndRoute(self.__WB_MANIFEST);

// ===== PUSH NOTIFICATIONS =====
self.addEventListener('push', function (event) {
  console.log('[SW] 🔔 Push event received at:', new Date().toISOString());
  console.log('[SW] 📊 Push event data available:', !!event.data);

  // Default fallback data
  let title = '📋 New Pick List';
  let body = 'بكلست جديدة';
  let url = '/';
  let icon = '/pwa-192x192.png';
  let badge = '/pwa-192x192.png';

  // Parse incoming data with multiple fallbacks
  if (event.data) {
    try {
      const parsed = event.data.json();
      console.log('[SW] 📦 Parsed push data:', JSON.stringify(parsed));
      
      title = parsed.title || title;
      body = parsed.body || parsed.message || body;
      url = parsed.url || parsed.link || url;
      icon = parsed.icon || icon;
      badge = parsed.badge || badge;
    } catch (e) {
      console.log('[SW] ⚠️ Failed to parse JSON, trying text:', e);
      try {
        const textData = event.data.text();
        console.log('[SW] 📝 Text data:', textData);
        body = textData || body;
      } catch (e2) {
        console.log('[SW] ⚠️ Failed to parse text, using defaults:', e2);
      }
    }
  } else {
    console.log('[SW] ℹ️ No push data received, using defaults');
  }

  const options = {
    body: body,
    icon: icon,
    badge: badge,
    tag: 'picklist-notification',
    renotify: true,
    requireInteraction: false,
    vibrate: [200, 100, 200, 100, 200],
    data: { 
      url: url, 
      timestamp: Date.now(),
      clickAction: url 
    },
  } as any;

  console.log('[SW] 🔔 Showing notification:', title);
  console.log('[SW] 📋 Options:', JSON.stringify(options));

  // CRITICAL: waitUntil ensures SW stays alive until notification is shown
  // This is what allows the notification to appear even when browser is closed
  event.waitUntil(
    self.registration.showNotification(title, options)
      .then(() => {
        console.log('[SW] ✅ Notification displayed successfully at', new Date().toISOString());
      })
      .catch((error) => {
        console.error('[SW] ❌ Failed to show notification:', error);
        console.error('[SW] ❌ Error details:', error.message, error.stack);
      })
  );
});

self.addEventListener('notificationclick', function (event) {
  console.log('[SW] 👆 Notification clicked:', event.notification.data);
  event.notification.close();

  // Get target URL from notification data
  const urlToOpen = event.notification.data?.clickAction || event.notification.data?.url || '/';
  console.log('[SW] 🔗 Opening URL:', urlToOpen);

  event.waitUntil(
    self.clients
      .matchAll({ type: 'window', includeUncontrolled: true })
      .then(function (clientList) {
        console.log('[SW] 🔍 Found clients:', clientList.length);
        
        // Check if there's already a window/tab open with the target URL
        for (const client of clientList) {
          if (client.url === urlToOpen && 'focus' in client) {
            console.log('[SW] ✅ Focusing existing window');
            return client.focus();
          }
        }
        
        // If no matching client, focus any client or open new window
        if (clientList.length > 0 && 'focus' in clientList[0]) {
          console.log('[SW] ✅ Focusing first client and navigating');
          return clientList[0].focus().then(() => clientList[0].navigate(urlToOpen));
        }
        
        // No clients open, open new window
        console.log('[SW] ✅ Opening new window');
        return self.clients.openWindow(urlToOpen);
      })
      .catch((error) => {
        console.error('[SW] ❌ Failed to handle notification click:', error);
      })
  );
});

// ===== BACKGROUND SYNC & KEEP-ALIVE =====

// Keep SW alive - respond to periodic sync if available
self.addEventListener('periodicsync', function (event: any) {
  console.log('[SW] 🔄 Periodic sync triggered:', event.tag);
  if (event.tag === 'keep-alive') {
    event.waitUntil(
      // Send a heartbeat to verify SW is alive
      fetch('/').then(() => {
        console.log('[SW] 💓 Heartbeat sent - SW is alive');
      }).catch(() => {
        console.log('[SW] ⚠️ Heartbeat failed but SW is still active');
      })
    );
  }
});

// Wake up on sync events (for offline support)
self.addEventListener('sync', function (event: any) {
  console.log('[SW] 🔄 Background sync triggered:', event.tag);
  event.waitUntil(Promise.resolve());
});

// Activate immediately and claim all clients
self.addEventListener('activate', function(event) {
  console.log('[SW] ✅ Service Worker activated at:', new Date().toISOString());
  event.waitUntil(
    self.clients.claim().then(() => {
      console.log('[SW] ✅ Claimed all clients');
    })
  );
});

// Listen to messages from clients (for debugging)
self.addEventListener('message', function(event) {
  console.log('[SW] 📨 Message received:', event.data);
  
  if (event.data && event.data.type === 'PING') {
    event.ports[0].postMessage({ type: 'PONG', timestamp: Date.now() });
  }
});
